INSERT INTO long_term_memory (
    id, tenant_id, agent_name, user_id, session_id, memory_type,
    content, content_vector_id, metadata_json, importance_score,
    is_auto, expire_time, access_count, last_access_time, is_deleted
) VALUES (
    #{id}, #{tenantId}, #{agentName}, #{userId}, #{sessionId}, #{memoryType},
    #{content}, #{contentVectorId}, #{metadata,typeHandler=com.jldaren.agent.ai.datascope.memory.typehandler.JsonMapTypeHandler},
    #{importanceScore}, #{isAuto}, #{expireTime}, #{accessCount}, #{lastAccessTime}, #{isDeleted}
)

mapper.select:
SELECT m.id, m.content, m.memory_type, m.importance_score, m.metadata_json, m.session_id, m.create_time, m.is_auto, MAX(1 - v.distance / 2) AS similarity_score FROM long_term_memory m INNER JOIN agent_scope_vector_store v ON m.content_vector_id = v.id WHERE m.is_deleted = 0 AND m.agent_name = #{agentName}
AND m.user_id = #{userId}
AND m.tenant_id = #{tenantId}
AND m.memory_type = #{memoryType}
AND (1 - v.distance / 2) >= #{threshold}
GROUP BY m.content ORDER BY similarity_score DESC, m.importance_score DESC LIMIT #{topK}

SELECT
    m.id,
    m.content,
    m.memory_type,
    m.importance_score,
    m.metadata_json,
    m.session_id,
    m.create_time,
    m.is_auto,
    MAX(1 - v.distance / 2) AS similarity_score
FROM long_term_memory m
INNER JOIN agent_scope_vector_store v ON m.content_vector_id = v.id
WHERE m.is_deleted = 0
  AND m.agent_name = #{agentName}

      AND m.user_id = #{userId}


      AND m.tenant_id = #{tenantId}


      AND m.session_id = #{sessionId}


      AND m.memory_type = #{memoryType}


      AND (1 - v.distance / 2) >= #{threshold}

GROUP BY m.content
ORDER BY similarity_score DESC, m.importance_score DESC
LIMIT #{topK}

SELECT * FROM long_term_memory
WHERE is_deleted = 0
  AND agent_name = #{agentName}

      AND user_id = #{userId}


      AND tenant_id = #{tenantId}


      AND memory_type = #{memoryType}

  AND content LIKE CONCAT('%', #{keyword}, '%')
ORDER BY importance_score DESC, create_time DESC

    LIMIT #{limit}

SELECT * FROM long_term_memory
WHERE is_deleted = 0
  AND agent_name = #{agentName}

      AND user_id = #{userId}


      AND tenant_id = #{tenantId}


      AND memory_type = #{memoryType}

ORDER BY importance_score DESC, create_time DESC

    LIMIT #{limit}

SELECT * FROM long_term_memory
WHERE is_deleted = 0
  AND agent_name = #{agentName}
  AND session_id = #{sessionId}

      AND user_id = #{userId}


      AND tenant_id = #{tenantId}

ORDER BY create_time ASC

SELECT COUNT(*) FROM long_term_memory
WHERE is_deleted = 0
  AND agent_name = #{agentName}

      AND user_id = #{userId}


      AND tenant_id = #{tenantId}

SELECT COUNT(*) FROM long_term_memory
WHERE is_deleted = 0
  AND agent_name = #{agentName}
  AND user_id = #{userId}
  AND content = #{content}

      AND tenant_id = #{tenantId}

LIMIT 1

SELECT * FROM long_term_memory
WHERE is_deleted = 0
  AND agent_name = #{agentName}
  AND user_id = #{userId}
  AND content LIKE CONCAT('%', #{keyword}, '%')

      AND tenant_id = #{tenantId}

ORDER BY create_time DESC
LIMIT 1

SELECT * FROM long_term_memory_config
WHERE agent_name = #{agentName}


          AND tenant_id = #{tenantId}


          AND tenant_id IS NULL


LIMIT 1

